mapper.select:
/* wms-wif-cmm-sql-oracle.xml - selectIfList 인터페이스 목록 조회 */ SELECT '0' AS CHK ,TCEM.IFCD ,TCEM.IFNM ,TCEM.IFDESC ,TCEM.CTKEY ,TMC.CTNM ,TCEM.OWKEY ,TCEM.ORD ,TCEM.USEYN ,TCEM.INSERTDATE ,TCEM.INSERTURKEY ,TCEM.UPDATEDATE ,TCEM.UPDATEURKEY FROM TWIF_CMM_EQIF_MGMT TCEM LEFT OUTER JOIN TWORK_MST_CT TMC ON TCEM.CTKEY = TMC.CTKEY WHERE 1 = 1
AND #{SEARCH_CONDITION}
ORDER BY ORD

/* wms-wif-cmm-sql-oracle.xml - selectIfListCount 인터페이스 목록 조회 */
SELECT COUNT(1)
  FROM TWIF_CMM_EQIF_MGMT TCEM
 WHERE 1 = 1

	AND  #{SEARCH_CONDITION}

/* wms-wif-cmm-sql-oracle.xml - selectIfCdDupCheckCount 인터페이스 중복체크 조회 */
SELECT COUNT(1)
  FROM TWIF_CMM_EQIF_MGMT
 WHERE 1 		= 1
   AND CTKEY 	= #{ctkey}
   AND OWKEY 	= #{owkey}
   AND IFCD 	= #{ifcd}

mapper.insert:
/* wms-wif-cmm-sql-oracle.xml - insertWifIfCd 인터페이스 코드 등록 */
INSERT INTO TWIF_CMM_EQIF_MGMT
(
	 IFCD
	,IFNM
	,IFDESC
	,CTKEY
	,OWKEY
	,ORD
	,USEYN
	,INSERTDATE
	,INSERTURKEY
	,UPDATEDATE
	,UPDATEURKEY
)
VALUES
(
	 #{ifcd}
	,#{ifnm}
	,#{ifdesc}
	,#{ctkey}
	,#{owkey}
	,#{ord}
	,#{useyn}
	,TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	,#{surkey}
	,TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	,#{surkey}
)

mapper.update:
/* wms-wif-cmm-sql-oracle.xml - updateWifIfCd 인터페이스 코드 수정 */
UPDATE TWIF_CMM_EQIF_MGMT
   SET IFNM 	= #{ifnm}
	   ,IFDESC 	= #{ifdesc}
	   ,USEYN 	= #{useyn}
	   ,ORD     = #{ord}
 WHERE CTKEY 	= #{ctkey}
   AND OWKEY 	= #{owkey}
   AND IFCD 	= #{ifcd}

mapper.delete:
/* wms-wif-cmm-sql-oracle.xml - deleteWifIfCd 인터페이스 코드 삭제 */
DELETE
  FROM TWIF_CMM_EQIF_MGMT
 WHERE CTKEY 	= #{ctkey}
   AND OWKEY 	= #{owkey}
   AND IFCD 	= #{ifcd}

mapper.select:
/* wms-wif-cmm-sql-oracle.xml - selectIfCdUseCheckCount 인터페이스 사용 체크 조회 */
SELECT COUNT(1)
  FROM TWIF_CMM_EQIF_MGMT
 WHERE 1 		= 1
   AND CTKEY 	= #{ctkey}
   AND OWKEY 	= #{owkey}
   AND IFCD 	= #{ifcd}

/* wms-wif-cmm-sql-oracle.xml - selectMaxOrd 인터페이스 목록관리 MAX ORD 조회 */
SELECT MAX(ORD)+1 AS ORD
  FROM TWIF_CMM_EQIF_MGMT
 WHERE CTKEY 	= #{ctkey}
   AND OWKEY 	= #{owkey}

/* wms-wif-cmm-sql-oracle.xml - selectWifInterfaceResult */
SELECT
        REQDATA
	   ,COALESCE(RESDATA, ERRMSG) AS RESDATA
  FROM TWIF_CMM_INTERFACE_LOG

	AND IFID = #{ifid}

/* wms-wif-cmm-sql-oracle.xml - selectIfValidContCount 인터페이스 항목 검증 이력 조회 COUNT */
SELECT COUNT(1)
  FROM TWIF_CMM_IFVL_HIS TCIH
 WHERE 1 = 1

	AND  #{SEARCH_CONDITION}

/* wms-wif-cmm-sql-oracle.xml - selectIfValidContList 인터페이스 항목 검증 이력 조회 LIST */ SELECT TCIH.HISSEQ , TCIH.CTKEY , CT.CTNM , TCIH.OWKEY , OW.OWNM , TCIH.IFCD , EQIF.IFNM AS IFCDNM , TCIH.IFID , TCIH.IFREQDT , TCIH.VALIDCONT , TCIH.INSERTDATE , TCIH.INSERTURKEY , TCIH.UPDATEDATE , TCIH.UPDATEURKEY FROM TWIF_CMM_IFVL_HIS TCIH LEFT OUTER JOIN TWORK_MST_CT CT ON TCIH.CTKEY = CT.CTKEY LEFT OUTER JOIN TWORK_MST_OW OW ON TCIH.OWKEY = OW.OWKEY LEFT OUTER JOIN TWIF_CMM_EQIF_MGMT EQIF ON TCIH.CTKEY = EQIF.CTKEY AND TCIH.OWKEY = EQIF.OWKEY AND TCIH.IFCD = EQIF.IFCD WHERE 1 = 1
AND #{SEARCH_CONDITION}
ORDER BY TCIH.HISSEQ DESC

/* wms-wif-cmm-sql-oracle.xml - selectIfApiSpecCount 인터페이스 API SPEC 조회 COUNT */
SELECT COUNT(1)
  FROM TWIF_CMM_API_SPEC TCAS
 WHERE 1 = 1

	AND  #{SEARCH_CONDITION}

/* wms-wif-cmm-sql-oracle.xml - selectIfApiSpecList 인터페이스 API SPEC 조회 LIST */ SELECT '0' AS CHK , APISEQ , TCAS.CTKEY , CT.CTNM , TCAS.OWKEY , OW.OWNM , TCAS.APICD , TCAS.APINM , TCAS.APIDESC , TCAS.APIKIND , TCAS.APITYPE , TCAS.APIMETHOD , TCAS.APIDOMAIN , TCAS.APIPORT , TCAS.APIURI , TCAS.SRCMODULE , TCAS.TGTMODULE , TCAS.ORD , TCAS.USEYN , TCAS.INSERTDATE , TCAS.INSERTURKEY , TCAS.UPDATEDATE , TCAS.UPDATEURKEY FROM TWIF_CMM_API_SPEC TCAS LEFT OUTER JOIN TWORK_MST_CT CT ON TCAS.CTKEY = CT.CTKEY LEFT OUTER JOIN TWORK_MST_OW OW ON TCAS.OWKEY = OW.OWKEY WHERE 1 = 1
AND #{SEARCH_CONDITION}
ORDER BY TCAS.ORD

/* wms-wif-cmm-sql-oracle.xml - selectIfApiSpecDupCheckCount 인터페이스 중복체크 조회 */
SELECT COUNT(1)
  FROM TWIF_CMM_API_SPEC
 WHERE 1 		= 1
   AND CTKEY 	= #{ctkey}
   AND OWKEY    = #{owkey}
   AND APICD 	= #{apicd}

/* wms-wif-cmm-sql-oracle.xml - selectApiSpecMaxOrd 인터페이스 Api Spec MAX ORD 조회 */
SELECT COALESCE(MAX(ORD), 0)+1 AS ORD
  FROM TWIF_CMM_API_SPEC
 WHERE CTKEY 	= #{ctkey}
   AND OWKEY    = #{owkey}

mapper.insert:
/* wms-wif-cmm-sql-oracle.xml - insertIfApiSpec 인터페이스 Api Spec INSERT 조회 */

	SELECT nextval('seq_twif_cmm_api_spec') AS APISEQ

INSERT INTO TWIF_CMM_API_SPEC
(
	APISEQ
	, CTKEY
	, OWKEY
	, APICD
	, APINM
	, APIDESC
	, APIKIND
	, APITYPE
	, APIMETHOD
	, APIDOMAIN
	, APIPORT
	, APIURI
	, SRCMODULE
	, TGTMODULE
	, ORD
	, USEYN
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
)
VALUES
(
	#{apiseq}
	, #{ctkey}
	, #{owkey}
	, #{apicd}
	, #{apinm}
	, #{apidesc}
	, #{apikind}
	, #{apitype}
	, #{apimethod}
	, #{apidomain}
	, #{apiport}
	, #{apiuri}
	, #{srcmodule}
	, #{tgtmodule}
	, #{ord}
	, #{useyn}
	, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	, #{surkey}
	, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	, #{surkey}
)

mapper.update:
/* wms-wif-cmm-sql-oracle.xml - updateIfApiSpec 인터페이스 Api Spec UPDATE 조회 */
UPDATE TWIF_CMM_API_SPEC
   SET APICD 		= #{apicd}
	   , APINM 		= #{apinm}
	   , APIDESC 	= #{apidesc}
	   , APIKIND 	= #{apikind}
	   , APITYPE 	= #{apitype}
	   , APIMETHOD 	= #{apimethod}
	   , APIDOMAIN 	= #{apidomain}
	   , APIPORT 	= #{apiport}
	   , APIURI 	= #{apiuri}
	   , SRCMODULE 	= #{srcmodule}
	   , TGTMODULE 	= #{tgtmodule}
	   , ORD        = #{ord}
	   , USEYN 		= #{useyn}
 WHERE 1 = 1
   AND CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND APISEQ = #{apiseq}

mapper.delete:
/* wms-wif-cmm-sql-oracle.xml - deleteApiSpec 인터페이스 Api Spec Delete */
DELETE
  FROM TWIF_CMM_API_SPEC
 WHERE CTKEY 	= #{ctkey}
   AND OWKEY 	= #{owkey}
   AND APISEQ 	= #{apiseq}

mapper.select:
/* wms-wif-cmm-sql-oracle.xml - selectInterfaceLogCount */
SELECT COUNT(1)
  FROM TWIF_CMM_INTERFACE_LOG


		AND #{SEARCH_CONDITION}

/* wms-wif-cmm-sql-oracle.xml - selectInterfaceLogList */
#{GRIDPAGING_ROWNUMTYPE_TOP}
SELECT B.* FROM (
	SELECT IFID
		,  IFNM
		,  REQDT
		,  IFTYPE
		,  CASE STATUS WHEN 'S' THEN 'S' ELSE 'F' END AS STATUS
		,  ISPROCESS
		,  TO_CHAR(INSERTDATE, 'YYYYMMDDHH24MISS') AS INSERTDATE
		,  TO_CHAR(UPDATEDATE, 'YYYYMMDDHH24MISS') AS UPDATEDATE
	  FROM TWIF_CMM_INTERFACE_LOG


			AND #{SEARCH_CONDITION}


	 ORDER BY IFID DESC
) B
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* wms-wif-cmm-sql-oracle.xml - selectInterfaceLog */
SELECT
      REQDATA
	, COALESCE(RESDATA, ERRMSG) AS RESDATA
FROM TWIF_CMM_INTERFACE_LOG

	AND IFID = #{ifid}
